  ('locality-6f0ba476-moex-00038', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '某甲為中華民國境內居住之個人，114年出售110年購買之A房屋，有交易所得50萬；同年並 出售100年購買之B房屋，有交易損失60萬。假設無其他交易事項，則某甲114年度綜合所得 稅結算申報可扣除之財產交易損失為若干？', '["60萬", "50萬", "30萬", "0元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "eefd9f150208", "answer_pdf_sha1": "af317452f60b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00039', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '甲君110年7月繼承其父親於107年2月購入的房地（繼承當時房地現值合計500萬元），併同 繼承其父親以該房地向金融機構貸款未償餘額900萬元，甲君於111年1月以1,800萬元出售該 房地，出售時土地漲價總數額300萬元，未提示相關必要費用，110年至111年物價指數未調整， 則甲君出售該房地需申報之課稅所得金額？', '["70萬元", "100萬元", "570萬元", "600萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "eefd9f150208", "answer_pdf_sha1": "af317452f60b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00040', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '某甲114年度遭遇水災，經國稅局派員勘查核定災害損失30萬元，若其獲得保險理賠10萬元、 救濟金3萬元，則某甲此筆災害損失可申報扣除之敘述，下列何者正確？', '["列舉扣除額、30萬元", "列舉扣除額、17萬元", "特別扣除額、30萬元", "特別扣除額、17萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "eefd9f150208", "answer_pdf_sha1": "af317452f60b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('locality-6f0ba476-moex-00041', 'locality-6f0ba476', 'locality-6f0ba476-moex-114-9bdab6d6', 'sub-locality-6f0ba476-03', NULL, 'single_choice', '依所得稅法第24條之5第3項規定，營利事業當年度房屋、土地交易損失，應先自當年度適用 相同稅率之房屋、土地交易所得中減除，減除不足部分，得自當年度適用不同稅率之房屋、土地 交易所得中減除，減除後尚有未減除餘額部分，下列處理方式何者正確？', '["可以在未來3年扣抵其房地合一交易所得", "可以在未來5年扣抵其房地合一交易所得", "可以在未來10年扣抵其房地合一交易所得", "可以適用所得稅法第39條盈虧互抵規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:01+00:00", "source_pdf_sha1": "eefd9f150208", "answer_pdf_sha1": "af317452f60b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "312", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "財稅行政"}'::jsonb, NULL),
